import CardIcon from '../assets/icons/CardIcon';

function CardValue() {
  return (
    <div className="w-full h-full flex items-center justify-center gap-32 bg-[#656c64] py-28">
      <div className="flex flex-col items-center">
        <CardIcon size="60" />
        <p className="text-white font-3xl ">Valor adulto</p>
        <p className="text-white font-3xl ">$70.000</p>
      </div>

      <div className="flex flex-col items-center">
        <CardIcon size="60" />
        <p className="text-white font-3xl ">Valor menor</p>
        <p className="text-white font-3xl ">$35.000</p>
      </div>
    </div>
  );
}

export default CardValue;
